"use client"

import * as React from "react"
import { cva } from "class-variance-authority"

import { cn } from "@/lib/utils"

// ──────────────────────────────────────────────
// Contexts
// ──────────────────────────────────────────────

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepState = "completed" | "active" | "pending"

type StepperItemContextValue = {
  step: number
  state: StepState
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ──────────────────────────────────────────────
// Stepper (root)
// ──────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-center" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ──────────────────────────────────────────────
// StepperItem
// ──────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperItem({ step, className, ...props }: StepperItemProps) {
  const { activeStep, orientation } = useStepper()
  const state: StepState =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-1 flex-row items-center gap-2"
            : "flex-col gap-2",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ──────────────────────────────────────────────
// StepperTrigger
// ──────────────────────────────────────────────

const stepperTriggerVariants = cva(
  "flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      state: {
        completed: "bg-primary text-primary-foreground",
        active: "border-2 border-primary bg-background text-primary",
        pending:
          "border-2 border-muted-foreground/30 bg-background text-muted-foreground",
      },
    },
    defaultVariants: {
      state: "pending",
    },
  }
)

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      className={cn(stepperTriggerVariants({ state }), className)}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// ──────────────────────────────────────────────
// StepperTitle
// ──────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ──────────────────────────────────────────────
// StepperDescription
// ──────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ──────────────────────────────────────────────
// StepperSeparator
// ──────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { state } = useStepperItem()
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-state={state}
      className={cn(
        "bg-border transition-colors",
        state === "completed" && "bg-primary",
        orientation === "horizontal"
          ? "h-px flex-1 min-w-8"
          : "mx-4 w-px min-h-8",
        className
      )}
      {...props}
    />
  )
}

// ──────────────────────────────────────────────
// StepperContent
// ──────────────────────────────────────────────

type StepperContentProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ──────────────────────────────────────────────
// Exports
// ──────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

