      className={cn(
        "bg-border transition-colors",
        state === "completed" && "bg-primary",
        orientation === "horizontal"
          ? "h-px flex-1 min-w-8"
          : "mx-4 w-px min-h-8",
        className
      )}
      {...props}
    />
  )
}

// ──────────────────────────────────────────────
// StepperContent
// ──────────────────────────────────────────────

type StepperContentProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn(className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ──────────────────────────────────────────────
// Exports
// ──────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

