"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    id: 1,
    title: "Account",
    content: "Enter your account details to get started.",
  },
  {
    id: 2,
    title: "Profile",
    content: "Set up your profile information.",
  },
  {
    id: 3,
    title: "Complete",
    content: "You've completed all the steps. Welcome aboard!",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="w-full max-w-lg space-y-6">
      <Stepper activeStep={activeStep}>
        {steps.map((step, index) => (
          <StepperItem key={step.id} step={step.id}>
            <StepperTrigger />
            <StepperTitle>{step.title}</StepperTitle>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </Stepper>

      {steps.map((step) => (
        <StepperContent key={step.id} step={step.id}>
          <div className="rounded-lg border p-4">
            <p className="text-sm text-muted-foreground">{step.content}</p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((prev) => Math.max(1, prev - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          onClick={() =>
            setActiveStep((prev) => Math.min(steps.length, prev + 1))
          }
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

